<script setup lang="ts">import{onMounted,ref}from'vue';import{api}from'../api/client';interface Job{id:string;original_name:string;status:string;error_message?:string;created_at:string;updated_at:string}const jobs=ref<Job[]>([]),loading=ref(true);async function load(){loading.value=true;try{jobs.value=(await api.get<Job[]>('/imports')).data}finally{loading.value=false}}function type(status:string){return status==='success'?'success':status==='failed'?'danger':'warning'}onMounted(load)</script>
<template><section v-loading="loading"><div class="head"><h1>导入任务</h1><el-button @click="load">刷新</el-button></div><el-table :data="jobs" empty-text="暂无导入记录"><el-table-column prop="original_name" label="文件名"/><el-table-column label="状态"><template #default="s"><el-tag :type="type(s.row.status)">{{s.row.status}}</el-tag></template></el-table-column><el-table-column prop="error_message" label="错误信息" show-overflow-tooltip/><el-table-column prop="created_at" label="创建时间"/></el-table></section></template>
<style scoped>.head{display:flex;align-items:center;justify-content:space-between}</style>
